import{_ as t,o as i,c as o,ag as a}from"./chunks/framework.B9unkguw.js";const h=JSON.parse('{"title":"Flight Safety (ArduPilot)","description":"","frontmatter":{},"headers":[],"relativePath":"en/qgc-user-guide/setup_view/ardupilot/flight_safety.md","filePath":"en/qgc-user-guide/setup_view/ardupilot/flight_safety.md"}'),n={name:"en/qgc-user-guide/setup_view/ardupilot/flight_safety.md"};function r(l,e,s,c,d,u){return i(),o("div",null,e[0]||(e[0]=[a('<h1 id="flight-safety-ardupilot" tabindex="-1">Flight Safety (ArduPilot) <a class="header-anchor" href="#flight-safety-ardupilot" aria-label="Permalink to &quot;Flight Safety (ArduPilot)&quot;">​</a></h1><p>The Flight Safety page configures Return to Launch behavior, geofence settings, and arming checks.</p><h2 id="return-to-launch" tabindex="-1">Return to Launch <a class="header-anchor" href="#return-to-launch" aria-label="Permalink to &quot;Return to Launch&quot;">​</a></h2><p>Settings vary by vehicle type:</p><ul><li><strong>RTL altitude</strong> — choose between returning at current altitude or a specified altitude (<code>RTL_ALT</code>)</li><li><strong>Loiter above home</strong> — optionally loiter at the return point before landing, with configurable loiter time (<code>RTL_LOIT_TIME</code>)</li><li><strong>Final landing altitude</strong> — altitude for the final descent phase (<code>RTL_ALT_FINAL</code>)</li><li><strong>Landing speed</strong> — descent rate during final landing (<code>LAND_SPD</code>)</li><li><strong>RTL radius</strong> — loiter radius at the return point (Plane, <code>RTL_RADIUS</code>; 0 uses the default waypoint loiter radius)</li><li><strong>Auto-land</strong> — automatically land after returning (Plane, <code>RTL_AUTOLAND</code>)</li></ul><h2 id="geofence" tabindex="-1">GeoFence <a class="header-anchor" href="#geofence" aria-label="Permalink to &quot;GeoFence&quot;">​</a></h2><ul><li><strong>Enable fence</strong> — turn the geofence on or off (<code>FENCE_ENABLE</code>)</li><li><strong>Fence type</strong> — bitmask selecting which limits to enforce: max altitude, min altitude, circle radius, polygon boundaries (<code>FENCE_TYPE</code>)</li><li><strong>Max altitude</strong> / <strong>Min altitude</strong> — altitude limits in meters</li><li><strong>Circle radius</strong> — cylindrical fence radius around home (<code>FENCE_RADIUS</code>)</li><li><strong>Fence margin</strong> — buffer distance before the fence boundary triggers an action (<code>FENCE_MARGIN</code>)</li><li><strong>Fence action</strong> — what to do when the fence is breached (RTL / Land / Report Only / etc.)</li><li><strong>Auto-enable</strong> — automatically enable the fence on arming or mode change (<code>FENCE_AUTOENABLE</code>)</li><li><strong>Return altitude</strong> (Plane) — altitude for the fence return path (<code>FENCE_RET_ALT</code>)</li><li><strong>Return to nearest rally point</strong> (Plane) — use the closest rally point instead of home (<code>FENCE_RET_RALLY</code>)</li></ul><h2 id="arming-checks" tabindex="-1">Arming Checks <a class="header-anchor" href="#arming-checks" aria-label="Permalink to &quot;Arming Checks&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Disabling arming checks can be dangerous. Only disable checks if you understand the safety implications.</p></div><ul><li><strong>Arming checks</strong> — bitmask of pre-arm checks to enforce (<code>ARMING_CHECK</code>). The first option enables/disables all checks.</li><li><strong>Skip checks</strong> — alternative bitmask to skip specific checks (<code>ARMING_SKIPCHK</code>)</li></ul>',10)]))}const f=t(n,[["render",r]]);export{h as __pageData,f as default};
